const accessToken = $json.access_token;
if (!accessToken) {
  throw new Error('Missing KiotViet access_token from OAuth response');
}

const retailer = $env.KIOTVIET_RETAILER;
if (!retailer) {
  throw new Error('Missing KIOTVIET_RETAILER env var');
}

const pageSize = 100;
let currentItem = 0;
const allProducts = [];

while (true) {
  const url = `https://public.kiotviet.vn/api/products?pageSize=${pageSize}&currentItem=${currentItem}&orderBy=createdDate&orderDirection=Desc&includeInventory=true`;
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url,
    json: true,
    headers: {
      Authorization: `Bearer ${accessToken}`,
      Retailer: retailer,
      'Content-Type': 'application/json'
    }
  });

  const pageData = Array.isArray(response?.data) ? response.data : [];
  if (pageData.length === 0) break;

  allProducts.push(...pageData);
  currentItem += pageSize;
}

return allProducts.map((p) => ({
  json: {
    kiotviet_product_id: p.id,
    product_code: p.code || null,
    product_name: p.name || null,
    barcode: p.barCode || null,
    category_id: p.categoryId || null,
    category_name: p.categoryName || null,
    base_price: p.basePrice ?? null,
    cost: p.cost ?? null,
    inventory_quantity: Array.isArray(p.inventories) && p.inventories.length > 0 ? Number(p.inventories[0].onHand || 0) : 0,
    is_active: p.isActive !== false
  }
}));
